import { ipcMain, shell } from 'electron';
import { SecureStorageService } from '../services/SecureStorageService';
import { ApiResult, KeychainAccessResult } from './types';
import { logger } from '../logger';

/**
 * Register system-level IPC handlers
 */
export function registerSystemHandlers(
  secureStorage: SecureStorageService
): void {
  console.log('[IPC] Registering system handlers');

  /**
   * Check keychain access
   */
  ipcMain.handle('system:check-keychain-access', async (_event, args?: { forceCheck?: boolean }): Promise<ApiResult<KeychainAccessResult>> => {
    try {
      logger.info('[IPC] Checking keychain access', args?.forceCheck ? '(force)' : '(cached)');
      const result = await secureStorage.checkKeychainAccess(args?.forceCheck);

      return {
        success: true,
        data: result,
      };
    } catch (error: any) {
      logger.error('[IPC] Failed to check keychain access:', error);
      return {
        success: false,
        error: error.message || 'Failed to check keychain access',
      };
    }
  });

  /**
   * Clear keychain access cache
   * Useful when user grants permission and wants to force a fresh check
   */
  ipcMain.handle('system:clear-keychain-cache', async (): Promise<ApiResult<void>> => {
    try {
      logger.info('[IPC] Clearing keychain cache');
      secureStorage.clearKeychainCache();

      return {
        success: true,
        data: undefined,
      };
    } catch (error: any) {
      logger.error('[IPC] Failed to clear keychain cache:', error);
      return {
        success: false,
        error: error.message || 'Failed to clear keychain cache',
      };
    }
  });

  /**
   * Open system keychain settings
   * - macOS: Keychain Access app
   * - Windows: Credential Manager
   * - Linux: Platform-specific settings
   */
  ipcMain.handle('system:open-keychain-settings', async (): Promise<ApiResult<void>> => {
    try {
      logger.info('[IPC] Opening keychain settings');
      const platform = process.platform;

      switch (platform) {
        case 'darwin': // macOS
          // Open Keychain Access application
          await shell.openPath('/System/Applications/Utilities/Keychain Access.app');
          break;

        case 'win32': // Windows
          // Open Credential Manager
          const { exec } = require('child_process');
          exec('control /name Microsoft.CredentialManager');
          break;

        case 'linux':
          // Linux varies by desktop environment, open system settings
          // This will open the default system settings app
          await shell.openPath('/usr/bin/gnome-control-center')
            .catch(() => shell.openPath('/usr/bin/systemsettings5'))
            .catch(() => logger.warn('[IPC] Could not open system settings on Linux'));
          break;

        default:
          throw new Error(`Unsupported platform: ${platform}`);
      }

      return {
        success: true,
        data: undefined,
      };
    } catch (error: any) {
      logger.error('[IPC] Failed to open keychain settings:', error);
      return {
        success: false,
        error: error.message || 'Failed to open keychain settings',
      };
    }
  });
}
